VALUES
  ('heelevel3-6f0ba476-moex-00532', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '認列於財務報表之要素係以貨幣形式量化，因此需要選擇衡量基礎。如果資產負債表中某項 負債依規定應採用現時成本衡量，則該負債應就下列何者衡量？', '["約當負債於衡量日將收取之對價", "約當負債於衡量日將收取之對價加上於該日將發生之交易成本", "約當負債於衡量日將收取之對價減去於該日將發生之交易成本", "預期隨個體履行負債有義務移轉之現金或其他經濟資源之現值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00533', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '下列有關財務報導觀念架構之敘述，何者正確？①適用認列條件及衡量觀念時所用之科目單', '["審慎性和中立描述相違背，所以觀念架構未將審慎性納入", "當企業收購另一 家公司之某產業部門時，該產業部門可能構成一報導個體", "折現值係衡量基礎的一種", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00534', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', 'X1年初甲公司銷貨予丙公司，產生一應收分期帳款，丙公司除頭期款$40,000外，X1年至X4 年每年底需支付$40,000，有效利率相當於10%。X1年底，甲公司X1年對該應收款認列之預 期信用減損損失共計$14,677。X2年底丙公司發生信用減損僅支付$34,000，甲公司估計X3與 X4年度分別僅可收取$32,000及$32,000，試問甲公司X2年對該應收款應認列於本期淨利之 預期信用減損損失金額為？（答案四捨五入至元）', '["($1,404)", "$5,207", "$22,000", "$36,667"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00535', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於20X0年度創立，員工每年有20天之帶薪休假，未休完之剩餘休假天數得以遞延使 用3年。每年休假時將優先使用當年度之休假天數，不足時再依序扣抵前1年度所遞延之剩 餘休假天數，未休完之剩餘休假將不會有現金補償。於20X0年12 月31日，甲公司有100 名員工，平均尚未休完之剩餘年假為7天。甲公司之管理階層預期此7天休假中，20X1年至 20X3年員工將依序使用3天、2天及1天之遞延休假，並放棄1天之遞延休假。此外，甲公 司預期2名員工將於20X1年離職（預估每位離職員工於20X1年度會使用23天休假），其餘 年度無人離職。下列敘述何者正確？', '["甲公司於20X0年12月31日應認列594天之其他長期員工福利負債，並全數分類為流動 負債", "甲公司於20X0年12月31日應認列594天之其他長期員工福利負債，並全數分類為非流 動負債", "甲公司於20X0年12月31日應認列594天之其他長期員工福利負債，並依預期使用年度是否 在一年內，分類為流動負債（預期使用在一年內）及非流動負債（預期使用在一年以上）", "甲公司於20X0年12月31日應認列600天之其他長期員工福利負債，其中300天分類為 流動負債，其餘300天分類為非流動負債 32470"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00536', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X4年7月1日將原始成本$400,000（交換當日資產公允價值為$140,000）之設備作 價$150,000與乙公司公允價值$160,000之設備進行交換，並支付現金$10,000。甲公司換出之 設備係於X2年1月1日購入，估計耐用年限5年，殘值為$25,000，採雙倍數餘額遞減法提 列折舊。另甲公司對換入之設備採年數合計法計提折舊，估計耐用年限4年，殘值為$25,000。 如上述交易應為不具商業實質，而甲公司誤判為具商業實質入帳，試分析上述事件將造成甲 公司X4年度損益高（低）估多少？', '["高估$19,840", "高估$22,800", "高估$24,800", "高估$34,800"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00537', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '下列關於取得客戶合約之增額成本敘述，何者錯誤？', '["取得合約之增額成本係企業為取得客戶合約所發生且若未取得該合約則不會發生之成本", "企業若預期可回收其取得客戶合約之增額成本，企業應將該等成本認列為資產", "取得客戶合約之增額成本所認列之資產須攤銷並評估減損", "作為一實務權宜作法，對於取得合約之增額成本認列之資產，企業可將取得合約之增額成 本於發生時認列為費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00538', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '乙公司是一家經營餐廳的營利事業，因為看好房地產景氣，在房地合一稅制實施後買入土地 並分類為投資性不動產，後續衡量採用公允價值模式，若該土地有公允價值變動之增值利益， 下列敘述何者正確？', '["所得稅費用增加、保留盈餘增加", "本期其他綜合淨利增加、其他權益增加", "遞延所得稅負債增加、保留盈餘減少", "本期所得稅負債增加、本期綜合淨利增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00539', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '乙公司於X1年12月30日將收到的承銷品列為進貨，並記入期末存貨，將使本期財務報表：', '["淨利低估，流動資產高估", "淨利低估，流動負債高估", "流動資產高估，流動負債高估", "不受影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00540', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '丙公司於X2年1月1日發行面額$100,000、利率11%、每年底付息一次、10年期公司債。 丙公司X5年1月1日應付公司債未攤銷折價的餘額為$4,564，X5年12月31日資產負債表 顯示應付公司債帳面金額為$95,888。請問該公司債之有效利率為何？（答案四捨五入至小數 點後二位）', '["13%", "15%", "10%", "12%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00541', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '某資訊顧問公司，於X1年初接獲客戶2年期之資訊安全專案服務，合約包價為1,000萬元， 估計總完工成本為600萬元，至X1年底已投入成本300萬元。請問該資訊顧問公司對此專 案服務於X1年可能認列收入若干元？ 甲、$0 乙、300萬元 丙、500萬元', '["僅丙正確", "僅乙、丙可能正確", "僅甲、乙可能正確", "甲、乙、丙均可能正確"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
